// // This module counts down on the falling edge of a clock and resets to 1 when a reset signal is deasserted.
module counter(clk, reset, count);  
    input clk;  
    input reset;  
    output reg [1:0] count;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 2'b00;  
        else  
            count <= count + 1;  
    end  
endmodule
